// // This comment suggests that the multiplexer selects the least significant bit of each input as the output.
module top_module(
    input [3:0] in_0,
    input [3:0] in_1,
    input [3:0] in_2,
    input [3:0] in_3,
    input [1:0] sel,
    output reg [3:0] out
);always @ (*) begin
        case (sel)
            2'b00: out = in_0;
            2'b01: out = in_1;
            2'b10: out = in_2;
            2'b11: out = in_3;
        endcase
    end

endmodule
